  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import { Stage } from 'react-konva';
  3→import { useNavigate } from 'react-router-dom';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getUniversePosts, getUserData } from '../../../API/Api';
  6→import supabase from '../../utils/supabaseClient';
  7→import useUniverseCamera from './hooks/useUniverseCamera';
  8→import useCosmicGravity from './hooks/useCosmicGravity';
  9→import DeepSpaceLayer from './layers/DeepSpaceLayer';
 10→import MidGalaxyLayer from './layers/MidGalaxyLayer';
 11→import NebulaLayer from './layers/NebulaLayer';
 12→import InteractiveLayer from './layers/InteractiveLayer';
 13→import WormholeLayer from './layers/WormholeLayer';
 14→import UniverseMinimap from './components/UniverseMinimap';
 15→import { extractSnippet, MIN_UNIVERSE_ZOOM, userHomeCoords } from './utils/starUtils';
 16→import {
 17→    buildSectorIndex,
 18→    computeGalaxyCentroids,
 19→    computeSectorKey,
 20→    getNeighborSectorKeys,
 21→} from './utils/cosmicPhysics';
 22→import { handleClickProfile } from '../../../helpers/handleClicks';
 23→import styles from './Universe.module.css';
 24→
 25→const SECTOR_SIZE = 2000;
 26→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 27→
 28→const Universe = () => {
 29→    const navigate = useNavigate();
 30→    const { user } = useAuth();
 31→    const userId = user?.userData?.[0]?.id || null;
 32→
 33→    const fetchDebounceRef = useRef(null);
 34→    const settleDebounceRef = useRef(null);
 35→    const lastSettledPayloadRef = useRef('');
 36→    const initialFetchResolvedRef = useRef(false);
 37→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
 38→    const ownGalaxyLookupStartedRef = useRef(false);
 39→
 40→    const [posts, setPosts] = useState(new Map());
 41→    const [selectedPost, setSelectedPost] = useState(null);
 42→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 43→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 44→    const [pulsingId, setPulsingId] = useState(null);
 45→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 46→    const [isInitialLoading, setIsInitialLoading] = useState(true);
 47→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
 48→    const [wormholes, setWormholes] = useState([]);
 49→    const [isWarping, setIsWarping] = useState(false);
 50→
 51→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
 52→    const [centroids, setCentroids] = useState([]);
 53→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 54→    const [similarPairs, setSimilarPairs] = useState([]);
 55→    const [starPulls, setStarPulls] = useState([]);
 56→
 57→    const {
 58→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
 59→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
 60→    } = useUniverseCamera(userId, hasOwnPosts);
 61→
 62→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 63→    const showTitles = zoom > 0.5;
 64→
 65→    // Sector partitioning for scalable local gravity math.
 66→    const postSectorIndex = useMemo(() => (
 67→        buildSectorIndex(
 68→            postArray,
 69→            (post) => ({
 70→                x: post?.display_x ?? post?.universe_x,
 71→                y: post?.display_y ?? post?.universe_y,
 72→            }),
 73→            SECTOR_SIZE
 74→        )
 75→    ), [postArray]);
 76→
 77→    const centerSectorKey = useMemo(
 78→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 79→        [centerWorld.x, centerWorld.y]
 80→    );
 81→
 82→    const activeSectorKeys = useMemo(
 83→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
 84→        [centerSectorKey]
 85→    );
 86→
 87→    const activePosts = useMemo(() => {
 88→        if (activeSectorKeys.size === 0) return postArray;
 89→
 90→        const next = [];
 91→        for (const key of activeSectorKeys) {
 92→            const bucket = postSectorIndex.get(key);
 93→            if (bucket?.length) next.push(...bucket);
 94→        }
 95→        return next;
 96→    }, [postArray, postSectorIndex, activeSectorKeys]);
 97→
 98→    const activePostIds = useMemo(() => {
 99→        const ids = new Set();
100→        for (const post of activePosts) {
101→            if (post?.id) ids.add(post.id);
102→        }
103→        return ids;
104→    }, [activePosts]);
105→
106→    const { centroidByUser } = useMemo(
107→        () => computeGalaxyCentroids(postArray),
108→        [postArray]
109→    );
110→
111→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
112→    const hashGalaxies = useMemo(() => {
113→        const seen = new Map();
114→        for (const post of postArray) {
115→            const uid = post.users?.id ?? post.user_id;
116→            if (!uid || seen.has(uid)) continue;
117→            const hash = userHomeCoords(uid);
118→            seen.set(uid, {
119→                userId: uid,
120→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
121→                x: hash.x,
122→                y: hash.y,
123→            });
124→        }
125→        return Array.from(seen.values());
126→    }, [postArray]);
127→
128→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
129→    const centroidTargets = useMemo(() => {
130→        const map = new Map();
131→        for (const c of centroids) {
132→            if (c.galaxy_x != null && c.galaxy_y != null) {
133→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
134→            }
135→        }
136→        return map;
137→    }, [centroids]);
138→
139→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
140→    const {
141→        galaxyPositions,
142→        starPullOffsets,
143→        isSettled,
144→        galaxyEdges: effectiveGalaxyEdges,
145→        hasEmbeddingGravity,
146→    } = useCosmicGravity({
147→        galaxies: hashGalaxies,
148→        centroidTargets,
149→        edges: galaxyEdges,
150→        posts: postArray,
151→        starPulls,
152→        centroidByUser,
153→        activeSectorKeys,
154→        activePostIds,
155→        sectorSize: SECTOR_SIZE,
156→    });
157→
158→    // ── Render galaxies = hash galaxies with animated positions ──────
159→    const galaxies = useMemo(() => {
160→        return hashGalaxies.map(g => {
161→            const animated = galaxyPositions.get(g.userId);
162→            return animated ? { ...g, x: animated.x, y: animated.y } : g;
163→        });
164→    }, [hashGalaxies, galaxyPositions]);
165→
166→    const getComputedStarPosition = useCallback((post) => {
167→        if (!post) return null;
168→
169→        const uid = post.users?.id ?? post.user_id;
170→        const hashGal = userHomeCoords(uid);
171→        const animGal = galaxyPositions.get(uid);
172→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
173→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
174→        const pull = starPullOffsets.get(post.id);
175→
176→        const baseX = post.universe_x ?? post.display_x;
177→        const baseY = post.universe_y ?? post.display_y;
178→        if (baseX == null || baseY == null) return null;
179→
180→        return {
181→            x: baseX + galDx + (pull?.dx ?? 0),
182→            y: baseY + galDy + (pull?.dy ?? 0),
183→        };
184→    }, [galaxyPositions, starPullOffsets]);
185→
186→    // Resolve logged-in user's galaxy target independently from viewport data.
187→    useEffect(() => {
188→        if (!userId) return;
189→        if (ownGalaxyLookupStartedRef.current) return;
190→
191→        ownGalaxyLookupStartedRef.current = true;
192→        let cancelled = false;
193→
194→        const resolveOwnGalaxyTarget = async () => {
195→            try {
196→                const { data, error } = await supabase
197→                    .from('galaxy_centroids')
198→                    .select('galaxy_x, galaxy_y')
199→                    .eq('user_id', userId)
200→                    .maybeSingle();
201→
202→                if (cancelled) return;
203→
204→                if (!error && data?.galaxy_x != null && data?.galaxy_y != null) {
205→                    setOwnGalaxyTarget({ x: data.galaxy_x, y: data.galaxy_y });
206→                    setHasOwnPosts(true);
207→                    return;
208→                }
209→            } catch (err) {
210→                console.warn('[universe] own centroid lookup failed:', err?.message || err);
211→            }
212→
213→            if (!cancelled) {
214→                setOwnGalaxyTarget(userHomeCoords(userId));
215→            }
216→        };
217→
218→        resolveOwnGalaxyTarget();
219→
220→        return () => {
221→            cancelled = true;
222→        };
223→    }, [userId]);
224→
225→    // One-time wormhole fetch on mount
226→    useEffect(() => {
227→        let cancelled = false;
228→
229→        const fetchWormholes = async () => {
230→            try {
231→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
232→                    similarity_threshold: 0.7,
233→                    min_distance: 0,
234→                    max_pairs: 30,
235→                });
236→                if (cancelled) return;
237→                if (error) {
238→                    console.warn('[universe] wormhole fetch error:', error.message);
239→                    return;
240→                }
241→                console.log('[universe] wormhole pairs:', data);
242→                if (Array.isArray(data) && data.length > 0) {
243→                    setWormholes(data);
244→                }
245→            } catch (err) {
246→                if (!cancelled) {
247→                    console.warn('[universe] wormhole fetch failed:', err?.message || err);
248→                }
249→            }
250→        };
251→
252→        fetchWormholes();
253→        return () => { cancelled = true; };
254→    }, []);
255→
256→    // Debounced fetch on camera/zoom change
257→    useEffect(() => {
258→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
259→
260→        fetchDebounceRef.current = setTimeout(async () => {
261→            const bounds = getViewportBounds();
262→            try {
263→                const result = await getUniversePosts(
264→                    bounds.minX,
265→                    bounds.maxX,
266→                    bounds.minY,
267→                    bounds.maxY,
268→                    200
269→                );
270→                if (result?.data) {
271→                    setPosts(prev => {
272→                        const next = new Map(prev);
273→                        for (const post of result.data) {
274→                            next.set(post.id, post);
275→                        }
276→                        return next;
277→                    });
278→                    if (userId && hasOwnPosts !== true) {
279→                        const ownsAny = result.data.some(p =>
280→                            (p.users?.id ?? p.user_id) === userId
281→                        );
282→                        if (ownsAny) setHasOwnPosts(true);
283→                    }
284→                }
285→                // Keep server gravity data as fallback when embeddings are absent in payload.
286→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
287→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
288→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
289→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
290→            } catch (err) {
291→                console.error('Failed to fetch universe posts:', err);
292→            } finally {
293→                if (!initialFetchResolvedRef.current) {
294→                    initialFetchResolvedRef.current = true;
295→                    setIsInitialLoading(false);
296→                }
297→            }
298→        }, 400);
299→
300→        return () => {
301→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
302→        };
303→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
304→
305→    const handleStarClick = useCallback((post) => {
306→        if (isFlying.current) return;
307→        setSelectedPost(post);
308→        setSelectedGalaxy(null);
309→        setGalaxyProfile(null);
310→
311→        const position = getComputedStarPosition(post);
312→        if (!position) return;
313→
314→        flyTo(position.x, position.y, 1.2, () => {
315→            setPulsingId(post.id);
316→            setTimeout(() => setPulsingId(null), 700);
317→        });
318→    }, [flyTo, getComputedStarPosition, isFlying]);
319→
320→    const handleGalaxyClick = useCallback(async (galaxy) => {
321→        if (isFlying.current) return;
322→        setSelectedGalaxy(galaxy);
323→        setSelectedPost(null);
324→        setGalaxyProfile(null);
325→        flyTo(galaxy.x, galaxy.y, 0.8);
326→
327→        try {
328→            const data = await getUserData(galaxy.userId);
329→            const profile = data?.userData?.[0] || null;
330→            setGalaxyProfile(profile);
331→        } catch (err) {
332→            console.error('Failed to fetch galaxy profile:', err);
333→        }
334→    }, [flyTo, isFlying]);
335→
336→    const handleReadPost = useCallback(() => {
337→        if (!selectedPost) return;
338→        navigate(`/home/post/${selectedPost.id}`);
339→    }, [selectedPost, navigate]);
340→
341→    const handleMinimapNavigate = useCallback((worldX, worldY, mode = 'fly') => {
342→        if (mode === 'drag') {
343→            jumpTo(worldX, worldY);
344→            return;
345→        }
346→        flyTo(worldX, worldY, zoom);
347→    }, [flyTo, jumpTo, zoom]);
348→
349→    // Enrich wormhole positions with live gravity-computed post coords
350→    const enrichedWormholes = useMemo(() => {
351→        return wormholes.map(wh => {
352→            const postA = posts.get(wh.post_a);
353→            const postB = posts.get(wh.post_b);
354→            const posA = postA ? getComputedStarPosition(postA) : null;
355→            const posB = postB ? getComputedStarPosition(postB) : null;
356→            return {
357→                ...wh,
358→                a_x: posA?.x ?? wh.a_x,
359→                a_y: posA?.y ?? wh.a_y,
360→                b_x: posB?.x ?? wh.b_x,
361→                b_y: posB?.y ?? wh.b_y,
362→            };
363→        });
364→    }, [wormholes, posts, getComputedStarPosition]);
365→
366→    // Find wormhole connection for a given post (if any)
367→    const getWormholeForPost = useCallback((postId) => {
368→        if (!postId || enrichedWormholes.length === 0) return null;
369→        for (const wh of enrichedWormholes) {
370→            if (wh.post_a === postId) return { wormhole: wh, side: 'a', targetTitle: wh.b_title };
371→            if (wh.post_b === postId) return { wormhole: wh, side: 'b', targetTitle: wh.a_title };
372→        }
373→        return null;
374→    }, [enrichedWormholes]);
375→
376→    const handleWormholeTravel = useCallback(() => {
377→        if (!selectedPost || isFlying.current) return;
378→        const match = getWormholeForPost(selectedPost.id);
379→        if (!match) return;
380→        const { wormhole, side } = match;
381→        const targetX = side === 'a' ? wormhole.b_x : wormhole.a_x;
382→        const targetY = side === 'a' ? wormhole.b_y : wormhole.a_y;
383→        setSelectedPost(null);
384→        setIsWarping(true);
385→        flyTo(targetX, targetY, zoom, () => setIsWarping(false));
386→    }, [selectedPost, getWormholeForPost, flyTo, isFlying, zoom]);
387→
388→    // One-time auto focus after first payload is loaded.
389→    useEffect(() => {
390→        if (!userId) return;
391→        if (isInitialLoading) return;
392→        if (hasAutoFocusedOwnGalaxyRef.current) return;
393→
394→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
395→        const target = ownGalaxy
396→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
397→            : (centroidTargets.get(userId) || ownGalaxyTarget);
398→
399→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
400→        if (!target) return;
401→
402→        hasAutoFocusedOwnGalaxyRef.current = true;
403→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
404→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
405→
406→    const settledPayload = useMemo(() => {
407→        if (!isSettled || activePosts.length === 0) return [];
408→
409→        const payload = [];
410→        for (const post of activePosts) {
411→            if (!post?.id) continue;
412→            const pos = getComputedStarPosition(post);
413→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
414→
415→            payload.push({
416→                post_id: post.id,
417→                settled_x: Math.round(pos.x * 100) / 100,
418→                settled_y: Math.round(pos.y * 100) / 100,
419→            });
420→        }
421→
422→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
423→        return payload;
424→    }, [activePosts, getComputedStarPosition, isSettled]);
425→
426→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
427→    useEffect(() => {
428→        if (!ENABLE_SETTLED_RPC_SAVE) return;
429→        if (!isSettled || settledPayload.length === 0) return;
430→
431→        const signature = JSON.stringify(settledPayload);
432→        if (signature === lastSettledPayloadRef.current) return;
433→
434→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
435→        settleDebounceRef.current = setTimeout(async () => {
436→            lastSettledPayloadRef.current = signature;
437→            try {
438→                const { error } = await supabase.rpc('save_universe_settled_positions', {
439→                    positions_payload: settledPayload,
440→                });
441→                if (error) {
442→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
443→                }
444→            } catch (err) {
445→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
446→            }
447→        }, 1200);
448→
449→        return () => {
450→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
451→        };
452→    }, [isSettled, settledPayload]);
453→
454→    useEffect(() => {
455→        return () => {
456→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
457→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
458→        };
459→    }, []);
460→
461→    return (
462→        <div className={`${styles.universeContainer} ${isDragging ? styles.grabbing : ''}`}>
463→            <button className={styles.backButton} onClick={() => navigate('/home')}>
464→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
465→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
466→                </svg>
467→                Back
468→            </button>
469→
470→            <div className={styles.coordsLabel}>
471→                {centerWorld.x}, {centerWorld.y}
472→            </div>
473→
474→            {isInitialLoading && (
475→                <div className={styles.loadingOverlay}>
476→                    <div className={styles.loadingCard}>
477→                        <div className={styles.loadingSpinner} />
478→                        <div className={styles.loadingText}>Loading universe...</div>
479→                    </div>
480→                </div>
481→            )}
482→
483→            <Stage
484→                ref={stageRef}
485→                width={stageSize.width}
486→                height={stageSize.height}
487→                {...stageEvents}
488→            >
489→                <DeepSpaceLayer layerProps={getLayerProps(0.1)} />
490→                <MidGalaxyLayer layerProps={getLayerProps(0.4)} />
491→                <NebulaLayer
492→                    layerProps={getLayerProps(0.85)}
493→                    galaxies={galaxies}
494→                    centroids={centroids}
495→                />
496→                {enrichedWormholes.length > 0 && (
497→                    <WormholeLayer
498→                        layerProps={getLayerProps(1.0)}
499→                        wormholes={enrichedWormholes}
500→                        zoom={zoom}
501→                    />
502→                )}
503→                <InteractiveLayer
504→                    layerProps={getLayerProps(1.0)}
505→                    posts={postArray}
506→                    galaxies={galaxies}
507→                    zoom={zoom}
508→                    showTitles={showTitles}
509→                    pulsingId={pulsingId}
510→                    onStarClick={handleStarClick}
511→                    onGalaxyClick={handleGalaxyClick}
512→                    galaxyPositions={galaxyPositions}
513→                    starPullOffsets={starPullOffsets}
514→                    similarPairs={similarPairs}
515→                    galaxyEdges={effectiveGalaxyEdges}
516→                    activePostIds={activePostIds}
517→                    useEmbeddingBridges={hasEmbeddingGravity}
518→                />
519→            </Stage>
520→
521→            {isWarping && <div className={styles.warpOverlay} />}
522→
523→            <UniverseMinimap
524→                galaxies={galaxies}
525→                camera={camera}
526→                zoom={zoom}
527→                stageSize={stageSize}
528→                onNavigate={handleMinimapNavigate}
529→            />
530→
531→            {selectedGalaxy && galaxyProfile && (
532→                <div className={styles.galaxyPreviewPanel}>
533→                    <button
534→                        className={styles.galaxyPreviewClose}
535→                        onClick={() => { setSelectedGalaxy(null); setGalaxyProfile(null); }}
536→                    >
537→                        &times;
538→                    </button>
539→                    <div
540→                        className={styles.galaxyPreviewBg}
541→                        style={galaxyProfile.background || {}}
542→                    />
543→                    <div className={styles.galaxyPreviewContent}>
544→                        <img
545→                            className={styles.galaxyPreviewAvatar}
546→                            src={galaxyProfile.image_url || '/assets/profile.jpg'}
547→                            alt=""
548→                        />
549→                        <div className={styles.galaxyPreviewHeading}>
550→                            This is {galaxyProfile.name || selectedGalaxy.name}'s galaxy
551→                        </div>
552→                        {galaxyProfile.bio && (
553→                            <div className={styles.galaxyPreviewBio}>{galaxyProfile.bio}</div>
554→                        )}
555→                        <button
556→                            className={styles.galaxyPreviewVisitBtn}
557→                            onClick={(e) => handleClickProfile(navigate)(e, userId, selectedGalaxy.userId)}
558→                        >
559→                            Visit Profile
560→                        </button>
561→                    </div>
562→                </div>
563→            )}
564→
565→            {selectedPost && (
566→                <div className={styles.previewPanel}>
567→                    <button
568→                        className={styles.previewClose}
569→                        onClick={() => setSelectedPost(null)}
570→                    >
571→                        &times;
572→                    </button>
573→                    <div className={styles.previewAuthor}>
574→                        <img
575→                            className={styles.previewAvatar}
576→                            src={selectedPost.users?.image_url || selectedPost.user_image_url || '/assets/profile.jpg'}
577→                            alt=""
578→                        />
579→                        <span className={styles.previewAuthorName}>
580→                            {selectedPost.users?.name || selectedPost.user_name || 'Anonymous'}
581→                        </span>
582→                    </div>
583→                    <div className={styles.previewTitle}>{selectedPost.title}</div>
584→                    <div className={styles.previewSnippet}>{extractSnippet(selectedPost)}</div>
585→                    <div className={styles.previewLikes}>
586→                        {(() => {
587→                            const count = selectedPost.like_count != null
588→                                ? selectedPost.like_count
589→                                : (Array.isArray(selectedPost.likes) && selectedPost.likes[0]?.count != null
590→                                    ? selectedPost.likes[0].count : 0);
591→                            return `${count} like${count !== 1 ? 's' : ''}`;
592→                        })()}
593→                    </div>
594→                    <div className={styles.previewActions}>
595→                        <button className={styles.previewReadBtn} onClick={handleReadPost}>
596→                            Read
597→                        </button>
598→                        {getWormholeForPost(selectedPost.id) && (
599→                            <div className={styles.wormholeBtnWrap}>
